"""Browser screen with dual-pane file browser."""

import logging
from pathlib import Path

from textual.app import ComposeResult
from textual.containers import Horizontal, Vertical
from textual.screen import Screen
from textual.widgets import Label

from termzilla.components.file_table import FileTable
from termzilla.components.status_bar import StatusBar
from termzilla.services.connection_manager import ConnectionManager
from termzilla.services.file_operations import LocalFileSystem, RemoteFileSystem
from termzilla.services.transfer_engine import TransferEngine

logger = logging.getLogger("termzilla")


class BrowserScreen(Screen):
    """Main browser screen with dual-pane layout."""

    BINDINGS = [
        ("ctrl+c", "quit", "Quit"),
        ("f5", "upload", "Upload"),
        ("f6", "download", "Download"),
        ("f3", "copy_file", "Copy"),
        ("f4", "move_file", "Move"),
        ("tab", "switch_pane", "Switch"),
        ("f7", "new_dir", "New Dir"),
    ]

    def compose(self) -> ComposeResult:
        with Horizontal(id="browser-layout"):
            with Vertical(id="local-pane"):
                yield Label("  Local", id="local-title")
                yield FileTable(id="local-table")
            with Vertical(id="remote-pane"):
                yield Label("  Remote", id="remote-title")
                yield FileTable(id="remote-table")
        yield StatusBar(id="status-bar")

    def on_mount(self) -> None:
        """Initialize the screen."""
        self._prompt_mode = None      # None, "copy", "move", "new_dir"
        self._prompt_buffer = ""
        self._prompt_source_path = None
        self._message = ""
        self._message_timer = 0

        self.connection_manager: ConnectionManager = getattr(
            self.app, "_connection_manager", None
        )

        self.local_fs = LocalFileSystem()
        self.remote_fs = None
        self.transfer_engine = None

        if self.connection_manager:
            self._init_remote()

        self.local_table = self.query_one("#local-table", FileTable)
        self.remote_table = self.query_one("#remote-table", FileTable)
        self.status_bar = self.query_one("#status-bar", StatusBar)

        self._refresh_local()
        if self.connection_manager:
            self._refresh_remote()

        self._refresh_status_bar()
        self.local_table.focus()
        self._focused_pane = "local"

    def _init_remote(self) -> None:
        """Initialize remote file system after connection."""
        sftp_client = self.connection_manager.get_sftp()
        self.remote_fs = RemoteFileSystem(sftp_client)
        self.transfer_engine = TransferEngine(sftp_client)
        self._refresh_remote()

    def _refresh_local(self) -> None:
        try:
            self.local_table.load_local_directory(self.local_fs.get_current_path())
        except Exception as e:
            logger.error(f"Failed to refresh local: {e}")

    def _refresh_remote(self) -> None:
        if not self.remote_fs:
            return
        try:
            sftp = self.connection_manager.get_sftp()
            self.remote_table.load_remote_directory(sftp, self.remote_fs.get_current_path())
        except Exception as e:
            logger.error(f"Failed to refresh remote: {e}")

    def _refresh_status_bar(self) -> None:
        """Update status bar with current state."""
        if self._prompt_mode:
            mode_labels = {"copy": "Copy to:", "move": "Move to:", "new_dir": "New dir name:"}
            label = mode_labels.get(self._prompt_mode, "")
            src_info = ""
            if self._prompt_source_path:
                src_name = Path(self._prompt_source_path).name
                src_info = f" ({src_name})"
            self.status_bar.override_text = (
                f" [bold]{label}[/] {self._prompt_buffer}{src_info}"
                f"  [dim]Enter=ok  Esc=cancel[/]"
            )
        elif self._message:
            self.status_bar.override_text = f" {self._message}"
        else:
            self.status_bar.override_text = ""
            self.status_bar.update_status(
                local_path=self.local_fs.get_current_path(),
                remote_path=self.remote_fs.get_current_path() if self.remote_fs else "",
                connection_status=self.connection_manager.get_display_string() if self.connection_manager else "Not connected",
            )
            return
        self.status_bar.refresh()

    # ── Actions ──────────────────────────────────────────────────────

    def action_switch_pane(self) -> None:
        if self._focused_pane == "local":
            self._focused_pane = "remote"
            self.remote_table.focus()
        else:
            self._focused_pane = "local"
            self.local_table.focus()

    def action_quit(self) -> None:
        if self.connection_manager:
            self.connection_manager.disconnect()
        self.app.exit()

    def action_copy_file(self) -> None:
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        name = table.get_selected_name()
        path = table.get_selected_path()
        if not name or name == ".." or not path:
            self._message = "Nothing selected"
            self._refresh_status_bar()
            return
        self._prompt_mode = "copy"
        self._prompt_buffer = ""
        self._prompt_source_path = path
        self._message = ""
        self._refresh_status_bar()

    def action_move_file(self) -> None:
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        name = table.get_selected_name()
        path = table.get_selected_path()
        if not name or name == ".." or not path:
            self._message = "Nothing selected"
            self._refresh_status_bar()
            return
        self._prompt_mode = "move"
        self._prompt_buffer = ""
        self._prompt_source_path = path
        self._message = ""
        self._refresh_status_bar()

    def action_new_dir(self) -> None:
        self._prompt_mode = "new_dir"
        self._prompt_buffer = ""
        self._prompt_source_path = None
        self._message = ""
        self._refresh_status_bar()

    # ── Key handling ─────────────────────────────────────────────────

    def on_key(self, event) -> None:
        key = event.key

        # Prompt mode handling
        if self._prompt_mode:
            if key == "enter":
                self._execute_prompt_action()
                event.stop()
                return
            elif key == "escape":
                self._prompt_mode = None
                self._prompt_buffer = ""
                self._prompt_source_path = None
                self._message = "Cancelled"
                self._refresh_status_bar()
                event.stop()
                return
            elif key == "backspace":
                self._prompt_buffer = self._prompt_buffer[:-1]
                self._refresh_status_bar()
                event.stop()
                return
            elif len(key) == 1 and key.isprintable():
                self._prompt_buffer += key
                self._refresh_status_bar()
                event.stop()
                return
            return

        # Normal mode
        if key == "enter":
            self._navigate_into()
            event.stop()
        elif key == "backspace":
            self._navigate_up()
            event.stop()
        elif key == "f5":
            self._upload_selected()
            event.stop()
        elif key == "f6":
            self._download_selected()
            event.stop()
        elif key == "delete":
            self._delete_selected()
            event.stop()
        elif key == "h":
            self._toggle_hidden()
            event.stop()

    # ── Navigation ───────────────────────────────────────────────────

    def _navigate_into(self) -> None:
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        fs = self.local_fs if self._focused_pane == "local" else self.remote_fs
        if not table.is_selected_directory():
            return
        path = table.get_selected_path()
        if not path:
            return
        try:
            fs.change_directory(path)
            if self._focused_pane == "local":
                self._refresh_local()
            else:
                self._refresh_remote()
            self._refresh_status_bar()
        except Exception as e:
            self._message = f"Error: {e}"
            self._refresh_status_bar()

    def _navigate_up(self) -> None:
        fs = self.local_fs if self._focused_pane == "local" else self.remote_fs
        parent = str(Path(fs.get_current_path()).parent)
        try:
            fs.change_directory(parent)
            if self._focused_pane == "local":
                self._refresh_local()
            else:
                self._refresh_remote()
            self._refresh_status_bar()
        except Exception as e:
            self._message = f"Error: {e}"
            self._refresh_status_bar()

    # ── Transfer ─────────────────────────────────────────────────────

    def _upload_selected(self) -> None:
        if self._focused_pane != "local" or not self.transfer_engine:
            return
        selected = self.local_table.get_selected_path()
        if not selected:
            return

        async def do_upload():
            remote_dest = f"{self.remote_fs.get_current_path()}/{Path(selected).name}"
            await self.transfer_engine.upload(local_path=selected, remote_path=remote_dest)
            self._refresh_remote()
            self._message = f"Uploaded {Path(selected).name}"
            self._refresh_status_bar()

        self.run_worker(do_upload())

    def _download_selected(self) -> None:
        if self._focused_pane != "remote" or not self.transfer_engine:
            return
        selected = self.remote_table.get_selected_path()
        if not selected:
            return

        async def do_download():
            local_dest = f"{self.local_fs.get_current_path()}/{Path(selected).name}"
            await self.transfer_engine.download(remote_path=selected, local_path=local_dest)
            self._refresh_local()
            self._message = f"Downloaded {Path(selected).name}"
            self._refresh_status_bar()

        self.run_worker(do_download())

    # ── File operations ──────────────────────────────────────────────

    def _delete_selected(self) -> None:
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        fs = self.local_fs if self._focused_pane == "local" else self.remote_fs
        name = table.get_selected_name()
        if not name or name == "..":
            return
        path = table.get_selected_path()
        if not path:
            return
        try:
            fs.delete(path)
            if self._focused_pane == "local":
                self._refresh_local()
            else:
                self._refresh_remote()
            self._message = f"Deleted {name}"
        except Exception as e:
            self._message = f"Delete error: {e}"
        self._refresh_status_bar()

    def _toggle_hidden(self) -> None:
        if self._focused_pane == "local":
            self.local_table.toggle_hidden_files()
            self._refresh_local()
        else:
            self.remote_table.toggle_hidden_files()
            self._refresh_remote()

    def _execute_prompt_action(self) -> None:
        """Execute the action from the prompt (copy/move/new_dir)."""
        dest = self._prompt_buffer.strip()
        if not dest:
            self._message = "Empty destination path"
            self._refresh_status_bar()
            return

        try:
            if self._prompt_mode == "copy":
                self._do_copy(dest)
            elif self._prompt_mode == "move":
                self._do_move(dest)
            elif self._prompt_mode == "new_dir":
                self._do_new_dir(dest)
        except Exception as e:
            logger.error(f"Prompt action failed: {e}")
            self._message = f"Error: {e}"
        finally:
            self._prompt_mode = None
            self._prompt_buffer = ""
            self._prompt_source_path = None
            self._refresh_status_bar()

    def _get_fs_and_table(self):
        """Get the appropriate fs and table for the focused pane."""
        fs = self.local_fs if self._focused_pane == "local" else self.remote_fs
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        return fs, table

    def _do_copy(self, dest: str) -> None:
        fs, table = self._get_fs_and_table()
        src = self._prompt_source_path
        name = table.get_selected_name()
        if dest.endswith("/") or dest == ".":
            dest = f"{dest.rstrip('/')}/{name}"
        fs.copy(src, dest)
        if self._focused_pane == "local":
            self._refresh_local()
        else:
            self._refresh_remote()
        self._message = f"Copied {name} -> {dest}"

    def _do_move(self, dest: str) -> None:
        fs, table = self._get_fs_and_table()
        src = self._prompt_source_path
        name = table.get_selected_name()
        if dest.endswith("/") or dest == ".":
            dest = f"{dest.rstrip('/')}/{name}"
        fs.rename(src, dest)
        if self._focused_pane == "local":
            self._refresh_local()
        else:
            self._refresh_remote()
        self._message = f"Moved {name} -> {dest}"

    def _do_new_dir(self, name: str) -> None:
        fs = self.local_fs if self._focused_pane == "local" else self.remote_fs
        dest = f"{fs.get_current_path()}/{name}"
        fs.create_directory(dest)
        if self._focused_pane == "local":
            self._refresh_local()
        else:
            self._refresh_remote()
        self._message = f"Created directory {name}"
